import { HealthService } from '../../services/health.service.js';
import { navigate } from '../../router.js';
import { buildSectionPage } from '../../utils/section-page.utils.js';
import './activity-edit/activity-edit.component.js';
import type { ActivityEdit, ActivitySourceMode } from './activity-edit/activity-edit.component.js';
import type { Activity } from '@motivation/shared';

export class HealthActivityEditScreen extends HTMLElement {
    private initialized = false;
    private idValue: string | null = null;
    private contentRoot: HTMLElement | null = null;
    private errorEl: HTMLElement | null = null;
    private loadingEl: HTMLElement | null = null;

    set entryId(value: string | null) {
        this.idValue = value;
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Edit workout', 'health', '/health');
        this.contentRoot = page.content;

        this.loadingEl = document.createElement('p');
        this.loadingEl.className = 'loading-text';
        this.loadingEl.textContent = 'Loading activity…';
        this.contentRoot.appendChild(this.loadingEl);

        this.errorEl = document.createElement('p');
        this.errorEl.className = 'error-text';
        this.errorEl.hidden = true;
        this.contentRoot.appendChild(this.errorEl);

        void this.loadActivity();
    }

    private async loadActivity(): Promise<void> {
        if (!this.idValue || !this.contentRoot) return;
        try {
            const activity = await HealthService.fetchActivity(this.idValue);
            if (!activity) {
                this.showError(`Activity ${this.idValue} not found.`);
                return;
            }
            this.renderEditor(activity);
        } catch (err) {
            console.error('Failed to load activity', err);
            this.showError(err instanceof Error ? err.message : 'Failed to load activity.');
        }
    }

    private renderEditor(activity: Activity): void {
        if (!this.contentRoot) return;
        this.loadingEl!.hidden = true;
        this.errorEl!.hidden = true;

        const editor = document.createElement('activity-edit') as ActivityEdit;
        editor.activity = activity;
        this.contentRoot.appendChild(editor);
        editor.sourceMode = resolveSourceMode(activity.source);

        editor.onSave = async (id, updates) => {
            try {
                await HealthService.updateActivity(id, updates);
                this.returnToDay(activity.date);
            } catch (err) {
                console.error('Failed to update activity', err);
                this.showError(err instanceof Error ? err.message : 'Failed to save.');
            }
        };

        editor.onDelete = async (id) => {
            try {
                await HealthService.deleteActivity(id);
                this.returnToDay(activity.date);
            } catch (err) {
                console.error('Failed to delete activity', err);
                this.showError(err instanceof Error ? err.message : 'Failed to delete.');
            }
        };
    }

    private returnToDay(date: string): void {
        navigate(`/health/day/${encodeURIComponent(date)}`, { history: 'replace' });
    }

    private showError(message: string): void {
        if (!this.errorEl || !this.loadingEl) return;
        this.loadingEl.hidden = true;
        this.errorEl.textContent = message;
        this.errorEl.hidden = false;
    }
}

function resolveSourceMode(source: Activity['source']): ActivitySourceMode {
    if (source === 'strava') return 'strava';
    if (source === 'calendar') return 'calendar';
    return 'manual';
}

customElements.define('health-activity-edit-screen', HealthActivityEditScreen);
